#include <bits/stdc++.h>
using namespace std;
int n;
int main(){
    string name;float temper;int cough,sum=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>name>>temper>>cough;
        if(temper>=37.5 && cough){
            cout<<name<<endl;
            sum++;
        }
    }
    cout<<sum;
    return 0;
}
